        books.add(createDemoBook("Così parlò Zarathustra", "Friedrich Nietzsche", "filosofici", "Il capolavoro filosofico-poetico in cui Nietzsche affida al profeta Zarathustra la propria visione del mondo: la morte di Dio, la dottrina del superuomo e quella dell'eterno ritorno. Attraverso uno stile visionario a metà tra il poema e il trattato filosofico, l'opera invita l'umanità a superare i vecchi valori per crearne di nuovi, in una delle riflessioni più influenti e discusse della storia del pensiero occidentale.", "https://m.media-amazon.com/images/I/71U4WaJU1UL._SL1500_.jpg", "newton"));
        books.add(createDemoBook("Il mondo come volontà e rappresentazione", "Arthur Schopenhauer", "filosofici", "L'opera che rivoluziona la filosofia ottocentesca proponendo una distinzione decisiva tra il mondo come appare ai nostri sensi e la sua sostanza più profonda, una volontà cieca e insaziabile che si manifesta in ogni forma di vita. Da questa visione pessimistica dell'esistenza, Schopenhauer sviluppa una riflessione sull'arte, la compassione e l'ascesi come possibili vie di liberazione dal dolore del volere.", "https://m.media-amazon.com/images/I/715g4UxcT3L._SL1500_.jpg", "newton"));
