        books.add(createDemoBook("Sorvegliare e punire. Nascita della prigione", "Michel Foucault", "filosofici", "Un'indagine storica e filosofica sulla nascita del sistema carcerario moderno, che ricostruisce il passaggio dai supplizi pubblici dell'antico regime alla disciplina invisibile e capillare delle istituzioni moderne. Foucault mostra come il potere non agisca più solo attraverso la repressione violenta, ma attraverso la sorveglianza costante e la normalizzazione dei corpi, in un'analisi che ha rivoluzionato il modo di pensare le istituzioni.", "https://m.media-amazon.com/images/I/71KEv1I4uYL._SL1184_.jpg", "einaudi"));
